t.script:
function toggleCfg(btn, id) {
    var el = document.getElementById(id);
    if (!el) return;
    var open = el.style.display === 'none' || !el.style.display;
    el.style.display = open ? 'block' : 'none';
    btn.innerHTML = open
        ? 'Hide Config'
        : 'View Config';
}
function switchTab(kid, name, link) {
    var base = 'tab-' + kid + '-';
    document.querySelectorAll('[id^="' + base + '"]').forEach(function(el) { el.style.display = 'none'; });
    var active = document.getElementById(base + name);
    if (active) active.style.display = 'block';
    var tabList = link.closest('ul');
    if (tabList) tabList.querySelectorAll('.nav-link').forEach(function(a) { a.classList.remove('active'); });
    link.classList.add('active');
}
function cp(id, btn) {
    var text = document.getElementById(id).textContent;
    navigator.clipboard.writeText(text).then(function() {
        btn.textContent = '✓ Copied'; btn.classList.add('btn-success'); btn.classList.remove('btn-secondary');
        setTimeout(function() { btn.textContent = 'Copy'; btn.classList.remove('btn-success'); btn.classList.add('btn-secondary'); }, 2500);
    });
}

function cp(id, btn) {
    var text = document.getElementById(id).textContent;
    var orig = btn.textContent;
    navigator.clipboard.writeText(text).then(function() {
        btn.textContent = '✓ Copied';
        btn.classList.add('btn-success'); btn.classList.remove('btn-secondary');
        setTimeout(function() {
            btn.textContent = orig;
            btn.classList.remove('btn-success'); btn.classList.add('btn-secondary');
        }, 2500);
    }).catch(function() {
        var ta = document.createElement('textarea');
        ta.value = text; document.body.appendChild(ta); ta.select();
        document.execCommand('copy'); document.body.removeChild(ta);
        btn.textContent = '✓ Copied';
        setTimeout(function() { btn.textContent = orig; }, 2500);
    });
}

document.getElementById('dl-btn').addEventListener('click', function() {
    var sections = [
        ['YOUR API KEY', 'key-code'],
        ['ChatGPT (paste as Server URL)', 'chatgpt-url'],
        ['Claude Code (run in terminal)', 'claude-code'],
        ['Cursor IDE (.cursor/mcp.json)', 'cursor-config'],
        ['Continue.dev (~/.continue/config.json)', 'continue-config'],
        ['Claude Desktop (claude_desktop_config.json)', 'desktop-config'],
        ['Gemini CLI (~/.gemini/settings.json)', 'gemini-config'],
        ['Codex CLI (~/.codex/config.yaml)', 'codex-config'],
        ['OpenCode (opencode.json)', 'opencode-config'],
        ['OpenAI Python bridge', 'openai-config'],
    ];
    var lines = ['# Odoo MCP Server — Connection Config', '# KEEP THIS FILE SECURE — treat like a password', ''];
    sections.forEach(function(s) {
        var el = document.getElementById(s[1]);
        lines.push('== ' + s[0] + ' ==');
        lines.push(el ? el.textContent.trim() : '');
        lines.push('');
    });
    var blob = new Blob([lines.join('\n')], {type: 'text/plain'});
    var a = document.createElement('a');
    a.href = URL.createObjectURL(blob); a.download = 'odoo-mcp-config.txt'; a.click();
});
